body:
While trying out workarounds for #5116, I came across this behavior:
Writing non-blocking assignments in tasks do not yield an `INITIALDLY` warning if the task belongs to a class, but it does if the task belongs to an interface or a module. Examples (compiled with `verilator --binary --build <file>.sv`):

Class tasks with virtual interfaces (Compiles and runs correctly):
```sv
interface INTF ();
    logic [7:0] field1; logic [7:0] field2;
endinterface

class driver;
    virtual INTF intf;

    function new(virtual INTF intf);
        this.intf = intf;
    endfunction

    task automatic set_fields();
        intf.field1 <= #5ns 42;
        #3ns;
        intf.field2 = 12;
    endtask
endclass

module top ();
    INTF intf ();
    driver drv = new(intf);

    initial begin
        $display("%d %d | Time: %t", intf.field1, intf.field2, $time);
        drv.set_fields();
        $display("%d %d | Time: %t", intf.field1, intf.field2, $time);
        #3ns;
        $display("%d %d | Time: %t", intf.field1, intf.field2, $time);
        $finish;
    end
endmodule
```

Interface tasks (`%Warning-INITIALDLY: initialdly_interface.sv:5:21`):
```sv
interface INTF ();
    logic [7:0] field1; logic [7:0] field2;

    task automatic set_fields();
        intf.field1 <= #5ns 42;
        #3ns;
        intf.field2 = 12;
    endtask
endinterface

module top ();
    INTF intf();

    initial begin
        $display("%d %d | Time: %t", intf.field1, intf.field2, $time);
        intf.set_fields();
        $display("%d %d | Time: %t", intf.field1, intf.field2, $time);
        #3ns;
        $display("%d %d | Time: %t", intf.field1, intf.field2, $time);
        $finish;
    end
endmodule
```

Module tasks (`%Warning-INITIALDLY: initialdly_module.sv:3:16`):
```sv
module driver( output logic [7:0] field1, output logic [7:0] field2 );
    task automatic set_fields();
        field1 <= #5ns 42;
        #3ns;
        field2 = 12;
    endtask
endmodule

module top ();
    logic [7:0] f1, f2;

    driver i_drv(f1, f2);

    initial begin
        $display("%d %d | Time: %t", f1, f2, $time);
        i_drv.set_fields();
        $display("%d %d | Time: %t", f1, f2, $time);
        #3ns;
        $display("%d %d | Time: %t", f1, f2, $time);
        $finish;
    end
endmodule
```

Is this behavior intended? If not, how hard would it be to make the non-blocking assignments work in at least `module` tasks as well?
